--- src/context/TenantContext.ts
+++ src/context/TenantContext.ts
@@ -1,28 +1,22 @@
-let _activeTenant: string | null = null;
+import { AsyncLocalStorage } from 'async_hooks';
+
+export const tenantLocalStorage = new AsyncLocalStorage<string>();

 export function setTenant(tenantId: string): void {
-  _activeTenant = tenantId;
+  throw new Error("setTenant is deprecated. Use TenantMiddleware for request-scoped tenant context.");
 }

 export function getTenant(): string {
-  if (_activeTenant === null) {
+  const tenantId = tenantLocalStorage.getStore();
+  if (tenantId === undefined || tenantId === null) {
     throw new Error(
       'TenantContext accessed outside of a tenant-scoped request. ' +
       'Ensure TenantMiddleware runs before any tenant-aware code.'
     );
   }
-  return _activeTenant;
+  return tenantId;
 }

 export function getTenantOrNull(): string | null {
-  return _activeTenant;
+  return tenantLocalStorage.getStore() ?? null;
 }

 export function clearTenant(): void {
-  _activeTenant = null;
+  throw new Error("clearTenant is deprecated. AsyncLocalStorage context is automatically managed.");
 }

 export function withTenant<T>(tenantId: string, fn: () => T): T {
-  const previous = _activeTenant;
-  _activeTenant = tenantId;
-  try {
-    return fn();
-  } finally {
-    _activeTenant = previous;
-  }
+  return tenantLocalStorage.run(tenantId, fn);
 }
---
--- src/middleware/TenantMiddleware.ts
+++ src/middleware/TenantMiddleware.ts
@@ -1,4 +1,4 @@
-import { setTenant, clearTenant } from '../context/TenantContext';
+import { tenantLocalStorage } from '../context/TenantContext';

 export interface TenantRequest {
   tenantId: string;
@@ -69,12 +69,12 @@
       throw new Error('Missing tenantId in request');
     }

-    setTenant(req.tenantId);
-    await verifyTenantExists(req.tenantId);
-
-    try {
-      await next();
-    } finally {
-      clearTenant();
-    }
+    await tenantLocalStorage.run(req.tenantId, async () => {
+      await verifyTenantExists(req.tenantId);
+      try {
+        await next();
+      } finally {
+        // The AsyncLocalStorage context automatically ends when the callback completes
+      }
+    });
   }
 }
